export const theme = {
  colors: {
    background: '#F3F6FB',
    backgroundElevated: '#FBFCFE',
    surface: '#FFFFFF',
    surfaceMuted: '#F7F9FD',
    stroke: '#E3E8F2',
    strokeStrong: '#CDD7E6',
    text: '#132238',
    textSecondary: '#5F7088',
    textTertiary: '#8B98AC',
    primary: '#0A84FF',
    primarySoft: '#E8F2FF',
    secondary: '#34C759',
    warning: '#FF9F0A',
    danger: '#FF453A',
    info: '#5AC8FA',
    navy: '#163456'
  },
  radius: {
    xs: 10,
    sm: 14,
    md: 18,
    lg: 24,
    xl: 30,
    pill: 999
  },
  spacing: {
    xs: 6,
    sm: 10,
    md: 14,
    lg: 18,
    xl: 24,
    xxl: 30
  }
} as const;

export const typography = {
  hero: {
    fontSize: 34,
    lineHeight: 40,
    fontWeight: '800' as const
  },
  title: {
    fontSize: 28,
    lineHeight: 34,
    fontWeight: '800' as const
  },
  section: {
    fontSize: 20,
    lineHeight: 24,
    fontWeight: '800' as const
  },
  body: {
    fontSize: 15,
    lineHeight: 22,
    fontWeight: '500' as const
  },
  caption: {
    fontSize: 12,
    lineHeight: 16,
    fontWeight: '700' as const
  }
} as const;
